class Solution {
public:
    string discountPrices(string sentence, int discount) {
        string res;
        size_t start = 0;
        while (start < sentence.size()) {
            size_t end = sentence.find(' ', start);
            if (end == string::npos) end = sentence.size();
            string word = sentence.substr(start, end - start);
            if (word.size() > 1 && word[0] == '$') {
                bool valid = true;
                for (size_t i = 1; i < word.size(); ++i) {
                    if (!isdigit(word[i])) { valid = false; break; }
                }
                if (valid) {
                    long long val = stoll(word.substr(1));
                    long double newVal = val * (100 - discount) / 100.0L;
                    char buf[50];
                    snprintf(buf, sizeof(buf), "$%.2Lf", newVal);
                    word = buf;
                }
            }
            res += word;
            if (end < sentence.size()) res += ' ';
            start = end + 1;
        }
        return res;
    }
};
